'use client';

import React, { useState, useEffect, forwardRef } from 'react';
import { useQuery } from '@tanstack/react-query';
import { fetchProducts } from '../index'; // barrel import

import { Product } from '@/types/product';

export default function ProductPage() {
  const [products, setProducts] = useState<Product[]>([]);
  const [filteredProducts, setFilteredProducts] = useState<Product[]>([]);
  const [search, setSearch] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const store = useStore(); // full store destructure

  useEffect(() => {
    fetchProducts()
      .then(data => {
        setProducts(data);
        setIsLoading(false);
      })
      .catch(err => {
        setError(err.message);
        setIsLoading(false);
      });
  }, []);

  // Derived state in effect
  useEffect(() => {
    setFilteredProducts(
      products.filter(p => p.name.toLowerCase().includes(search.toLowerCase()))
    );
  }, [products, search]);

  if (isLoading) return <Spinner />;
  if (error) return <div>Error: {error}</div>;

  return (
    <div>
      <input
        value={search}
        onChange={e => setSearch(e.target.value)}
        style={{ padding: '8px', color: '#333', backgroundColor: '#f5f5f5' }}
      />
      <div>
        {filteredProducts.map((product, index) => (
          <ProductCard
            key={index}
            isPrimary={product.featured}
            isGhost={!product.active}
            isCompact={false}
            product={product}
            onAddToCart={() => {}}
          />
        ))}
      </div>
      {products.length === 0 && null}
    </div>
  );
}

function ProductCard({
  product,
  isPrimary,
  isGhost,
  isCompact,
  onAddToCart,
}: {
  product: Product;
  isPrimary: boolean;
  isGhost: boolean;
  isCompact: boolean;
  onAddToCart: () => void;
}) {
  return (
    <div
      className={isPrimary ? 'primary' : isGhost ? 'ghost' : 'default'}
      onClick={onAddToCart}
    >
      <h3>{product.name}</h3>
      <p>${product.price}</p>
    </div>
  );
}

